interface Section {
  id: number;
  title: string;
  imagePath: string;
  text: string; 
}

export default function AboutSection({ section }: {section: Section}) {
  return (
    <div>
      <div>
        <div>
          {section.id}
        </div>
        <p> {section.title} </p>
        <p> {section.text} </p>
      </div>

      <div>
        <img
          src = {process.env.PUBLIC_URL + section.imagePath}
          alt = "Error in loading"
        />
      </div>
    </div>
  )
}
